#include<bits/stdc++.h>
using namespace std;
vector<pair<int,int>> mp[3000010];
int s,t,n,m,a[1010][1010],b[1010][1010],c[1010][1010];
int id[1010][1010][3],totp;
int p(int x,int y,int v)
{
    if(!id[x][y][v])
    {
        id[x][y][v]=++totp;
    }
    return id[x][y][v];
}
void add(int u,int v,int w)
{
    mp[u].push_back({v,w});
    mp[v].push_back({u,w});
}
int dis[3000010];
bool vis[3000010];
void dijkstra()
{
    memset(dis,0x3f,sizeof(dis));
    dis[s]=0;
    priority_queue<pair<int,int>> q;
    q.push({0,s});
    while(!q.empty())
    {
        int t=q.top().second;
        q.pop();
        if(vis[t])
        {
            continue;
        }
        vis[t]=false;
        for(auto i:mp[t])
        {
            int v=i.first,val=i.second;
            if(dis[v]>dis[t]+val)
            {
                dis[v]=dis[t]+val;
                q.push({-dis[v],v});
            }
        }
    }
}
int main()
{
    s=++totp;
    t=++totp;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<m;j++)
        {
            scanf("%d",&a[i][j]);
            if(i==1)
            {
                add(p(i,j,1),t,a[i][j]);
            }
            else if(i==n)
            {
                add(s,p(i-1,j,2),a[i][j]);
            }
            else
            {
                add(p(i,j,1),p(i-1,j,2),a[i][j]);
            }
        }
    }
    for(int i=1;i<n;i++)
    {
        for(int j=1;j<=m;j++)
        {
            scanf("%d",&b[i][j]);
            if(j==1)
            {
                add(s,p(i,j,2),b[i][j]);
            }
            else if(j==m)
            {
                add(p(i,j-1,1),t,b[i][j]);
            }
            else
            {
                add(p(i,j-1,1),p(i,j,2),b[i][j]);
            }
        }
    }
    for(int i=1;i<n;i++)
    {
        for(int j=1;j<m;j++)
        {
            scanf("%d",&c[i][j]);
            add(p(i,j,2),p(i,j,1),c[i][j]);
        }
    }
    dijkstra();
    printf("%d",dis[t]);
    return 0;
}
